import { Linking } from 'react-native';
import { NavigationContainerRef } from '@react-navigation/native';

let navigationRef: NavigationContainerRef<any> | null = null;

const deepLinkHandler = (url: string) => {
  try {
    const { host, path, queryParams } = parseDeepLink(url);
    
    // Validate host
    if (host !== 'myapp') {
      console.warn('Invalid host in deep link:', host);
      return;
    }
    
    // Route validation and authorization
    const route = path.split('/')[1];
    
    switch (route) {
      case 'profile':
        handleProfileRoute(path, queryParams);
        break;
      case 'payment':
        handlePaymentRoute(path, queryParams);
        break;
      default:
        console.warn('Unknown route in deep link:', route);
    }
  } catch (error) {
    console.error('Error handling deep link:', error);
  }
};

const parseDeepLink = (url: string) => {
  const urlObj = new URL(url);
  return {
    host: urlObj.host,
    path: urlObj.pathname,
    queryParams: Object.fromEntries(urlObj.searchParams.entries())
  };
};

const handleProfileRoute = (path: string, queryParams: Record<string, string>) => {
  // Validate user ID parameter
  const userId = path.split('/')[2];
  if (!userId || isNaN(parseInt(userId))) {
    console.warn('Invalid user ID in profile deep link');
    return;
  }
  
  // Authorization check - only allow access to own profile or admin
  const currentUser = getCurrentUser(); // Assume this function exists
  if (currentUser && (currentUser.id === userId || currentUser.role === 'admin')) {
    navigationRef?.navigate('Profile', { userId });
  } else {
    console.warn('Unauthorized access attempt to profile:', userId);
  }
};

const handlePaymentRoute = (path: string, queryParams: Record<string, string>) => {
  // Validate payment action
  const action = path.split('/')[2];
  if (!['confirm', 'cancel', 'status'].includes(action)) {
    console.warn('Invalid payment action:', action);
    return;
  }
  
  // Validate payment ID parameter
  const paymentId = queryParams.paymentId;
  if (!paymentId || !isValidPaymentId(paymentId)) {
    console.warn('Invalid payment ID in payment deep link');
    return;
  }
  
  // Authorization check for payment routes
  const currentUser = getCurrentUser();
  if (currentUser) {
    navigationRef?.navigate('Payment', { 
      action, 
      paymentId,
      userId: currentUser.id
    });
  } else {
    console.warn('Unauthorized access attempt to payment route');
  }
};

const isValidPaymentId = (id: string) => {
  // Simple validation - in production use proper validation
  return typeof id === 'string' && id.length > 10 && /^[a-zA-Z0-9_-]+$/.test(id);
};

const getCurrentUser = () => {
  // Mock implementation - replace with actual auth logic
  return { id: '123', role: 'user' };
};

// Setup deep link handling
const setupDeepLinking = () => {
  // Handle initial deep link
  Linking.getInitialURL().then((url) => {
    if (url) {
      deepLinkHandler(url);
    }
  });
  
  // Handle deep links when app is running
  Linking.addEventListener('url', (event) => {
    deepLinkHandler(event.url);
  });
};

